external_knowledge:
- "beacon lights the path to victory": metaphor for the party that wins the election by securing the highest number of votes;
- "soaring high with the most votes": metaphorical expression for leading in terms of vote count;
- "date they claimed their banner": the official result date of the election;
- "share of the voting populace": the voter turnout percentage;
- "standing among their rivals": the rank of the winning party in the election.

sql:
SELECT COUNT(DISTINCT user_id) AS distinct_active_users
FROM user_access_logs
WHERE timestamp > datetime('now', '-30 days');

SELECT headquarters, COUNT(*) 
FROM parties 
GROUP BY headquarters;

SELECT DISTINCT party_name
FROM parties
WHERE party_id IN (
    SELECT DISTINCT from_party_id
    FROM vote_transfers
);

SELECT location, COUNT(DISTINCT type_id) AS number_of_election_types
FROM elections
GROUP BY location;

SELECT SUM(total_votes) AS total_votes
FROM votes
WHERE party_id = 1;
